import { registerToDefault } from '../registry';
import type { SDUIComponentRenderer } from '../models';

import HeadingAdapter from './HeadingAdapter';
import TextAdapter from './TextAdapter';
import BalanceDisplayAdapter from './BalanceDisplayAdapter';
import PointsInputAdapter from './PointsInputAdapter';
import ButtonAdapter from './ButtonAdapter';
import LinkAdapter from './LinkAdapter';
import AlertAdapter from './AlertAdapter';
import ListTextIconAdapter from './ListTextIconAdapter';
import SeparatorAdapter from './SeparatorAdapter';
import IconTextRowAdapter from './IconTextRowAdapter';
import SectionHeadingAdapter from './SectionHeadingAdapter';
import RichTextAdapter from './RichTextAdapter';
import VoucherCardAdapter from './VoucherCardAdapter';
import EmptyStateAdapter from './EmptyStateAdapter';
import PointsCardAdapter from './PointsCardAdapter';
import TabBarAdapter from './TabBarAdapter';
import TransactionItemAdapter from './TransactionItemAdapter';
import DateSeparatorAdapter from './DateSeparatorAdapter';

// FIXME: use something like "props: DUIProps<Foo, Bar>" during component
//  creation in order to avoid eliminate the use of "as SDUIComponentRenderer"
const adapters: Record<string, SDUIComponentRenderer> = {
  heading: HeadingAdapter as SDUIComponentRenderer,
  text: TextAdapter as SDUIComponentRenderer,
  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
  points_input: PointsInputAdapter as SDUIComponentRenderer,
  button: ButtonAdapter as SDUIComponentRenderer,
  link: LinkAdapter as SDUIComponentRenderer,
  alert: AlertAdapter as SDUIComponentRenderer,
  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
  separator: SeparatorAdapter as SDUIComponentRenderer,
  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
  rich_text: RichTextAdapter as SDUIComponentRenderer,
  voucher_card: VoucherCardAdapter as SDUIComponentRenderer,
  empty_state: EmptyStateAdapter as SDUIComponentRenderer,
  points_card: PointsCardAdapter as SDUIComponentRenderer,
  tab_bar: TabBarAdapter as SDUIComponentRenderer,
  transaction_item: TransactionItemAdapter as SDUIComponentRenderer,
  date_separator: DateSeparatorAdapter as SDUIComponentRenderer,
};

export function registerAllAdapters(): void {
  Object.entries(adapters).forEach(([type, renderer]) => {
    registerToDefault(type, renderer);
  });
}

export { adapters };

import React from 'react';
import { ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Box,
  Button,
  Header,
  Icon,
  ListTextIcon,
  Skeleton,
  Text,
} from '@semparar/design-system-app';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';

interface CashbackInvoiceItem {
  type: 'default';
  icon: string;
  iconColor: string;
  iconColorShape: string;
  description: string;
}

function buildInvoiceItems(
  pointsQuantity: number,
  conversionFactor: number,
): CashbackInvoiceItem[] {
  const finalPrice = pointsQuantity * conversionFactor;
  const formattedPrice = new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(finalPrice);

  return [
    {
      type: 'default',
      icon: 'icon-switch-vertical',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: `Cada ${pointsQuantity} pontos valem ${formattedPrice} no cashback`,
    },
    {
      type: 'default',
      icon: 'icon-calendar',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Você define quanto cashback quer aplicar na sua fatura aberta',
    },
    {
      type: 'default',
      icon: 'icon-payment-invoice',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
    },
    {
      type: 'default',
      icon: 'icon-clock',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: 'O cashback acontece em até 72h',
    },
  ];
}

function ErrorState({ onRetry }: { onRetry: () => void }) {
  return (
    <Box flex={1} justify="center" align="center" pd="innerLarge">
      <Icon name="icon-circle-alert" color="DENY_COLOR_01" size={48} />
      <Text type="paragraphXXXL" align="center" mt="smaller" mb="xxxs">
        Ops, algo deu errado...
      </Text>
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mb="smaller"
      >
        Não foi possível carregar as informações. Por favor, tente novamente.
      </Text>
      <Button text="Tentar novamente" onPress={onRetry} />
    </Box>
  );
}

function InvoiceCashbackOnboardingWrapper({
  pointsQuantity = 15320,
  conversionFactor = 0.01,
  isLoading = false,
  hasError = false,
}: {
  pointsQuantity?: number;
  conversionFactor?: number;
  isLoading?: boolean;
  hasError?: boolean;
}) {
  const items = buildInvoiceItems(pointsQuantity, conversionFactor);

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Cashback na fatura"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        isOption={false}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        {hasError ? (
          <ErrorState onRetry={() => {}} />
        ) : (
          <>
            <Box ml="smaller" mr="smaller">
              <Text
                color="INTENSE_COLOR_05"
                testID="invoice-cashback-main-title"
                type="headingMDL"
                mt="smaller"
              >
                Use pontos para pagar menos na fatura
              </Text>
            </Box>

            {isLoading ? (
              items.map((_, index) => (
                <Box pd="innerLarge" key={`skeleton-${index}`}>
                  <Skeleton width={350} height={60} />
                </Box>
              ))
            ) : (
              <>
                <Box ml="nano" mr="nano" flex={1} justify="flex-start">
                  <ListTextIcon
                    items={items}
                    ml="nano"
                    mr="xs"
                    mt="xxs"
                    type="list"
                  />
                </Box>

                <Box ml="smaller" mr="smaller">
                  <Button
                    text="Continuar"
                    mt="large"
                    mb="small"
                    onPress={() => {}}
                    testID="invoice-cashback-button"
                  />
                </Box>
              </>
            )}
          </>
        )}
      </ScrollView>
    </Box>
  );
}

const meta: Meta<typeof InvoiceCashbackOnboardingWrapper> = {
  title: 'Screens/InvoiceCashbackOnboarding',
  component: InvoiceCashbackOnboardingWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    pointsQuantity: {
      control: { type: 'number' },
      description: 'Available points quantity for conversion display',
    },
    conversionFactor: {
      control: { type: 'number', step: 0.001 },
      description: 'Points to BRL conversion factor',
    },
    isLoading: {
      control: { type: 'boolean' },
      description: 'Loading skeleton state',
    },
    hasError: {
      control: { type: 'boolean' },
      description: 'API error state',
    },
  },
};

export default meta;
type Story = StoryObj<typeof InvoiceCashbackOnboardingWrapper>;

export const Loaded: Story = {
  name: 'Loaded (15.320 pts)',
  args: {
    pointsQuantity: 15320,
    conversionFactor: 0.01,
    isLoading: false,
    hasError: false,
  },
};

export const Loading: Story = {
  name: 'Loading State',
  args: {
    pointsQuantity: 15320,
    conversionFactor: 0.01,
    isLoading: true,
    hasError: false,
  },
};

export const Error: Story = {
  name: 'Error State',
  args: {
    hasError: true,
  },
};

