import React, { useState } from 'react';
import { ScrollView, View, Pressable } from 'react-native';
import {
  Text,
  Box,
  Button,
  Header,
  ListTextIcon,
  SeparatorHorizontal,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
import {
  onboardingCashback,
  onboardingVoucherAbastecimento,
  onboardingVoucherEstacionamento,
} from '../services/sdui/mocks';

registerAllAdapters();

type ProductVariant = 'cashback' | 'abastecimento' | 'estacionamento';

const SCREENS: Record<ProductVariant, SDUIScreen> = {
  cashback: onboardingCashback,
  abastecimento: onboardingVoucherAbastecimento,
  estacionamento: onboardingVoucherEstacionamento,
};

const LABELS: Record<ProductVariant, string> = {
  cashback: 'Cashback',
  abastecimento: 'Abastecimento',
  estacionamento: 'Estacionamento',
};

const VARIANTS: ProductVariant[] = ['cashback', 'abastecimento', 'estacionamento'];

function ProductToggle({
  selected,
  onSelect,
}: {
  selected: ProductVariant;
  onSelect: (v: ProductVariant) => void;
}) {
  return (
    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
      {VARIANTS.map(v => (
        <Pressable
          key={v}
          onPress={() => onSelect(v)}
          style={{
            paddingHorizontal: 16,
            paddingVertical: 8,
            borderRadius: 20,
            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
          }}
        >
          <Text
            type="paragraphMDM"
            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
          >
            {LABELS[v]}
          </Text>
        </Pressable>
      ))}
    </View>
  );
}

function OnboardingDemo() {
  const [variant, setVariant] = useState<ProductVariant>('cashback');
  const screen = useSDUIJsonEditor(SCREENS[variant]);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 420 }}>
        <Text type="headingMDL" mb="nano">
          SDUI: Onboarding
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Same ScreenRenderer, different JSON per product. Switch products to see
          how a single renderer handles Cashback, Abastecimento, and
          Estacionamento onboarding — no code changes needed.
        </Text>

        <ProductToggle selected={variant} onSelect={setVariant} />

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <ScreenRenderer screen={screen} />
        </Box>
      </View>
    </ScrollView>
  );
}

function RealScreenPreview() {
  const items = [
    {
      type: 'default',
      icon: 'icon-switch-vertical',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: 'Cada 15320 pontos valem R$ 153,20 no cashback',
    },
    {
      type: 'default',
      icon: 'icon-calendar',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Você define quanto cashback quer aplicar na sua fatura aberta',
    },
    {
      type: 'default',
      icon: 'icon-payment-invoice',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description:
        'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
    },
    {
      type: 'default',
      icon: 'icon-clock',
      iconColor: 'BRAND_BASE_01',
      iconColorShape: 'INTENSE_COLOR_01',
      description: 'O cashback acontece em até 72h',
    },
  ];

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Cashback na fatura"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        isOption={false}
      />
      <Box ml="smaller" mr="smaller">
        <Text
          color="INTENSE_COLOR_05"
          type="headingMDL"
          mt="smaller"
        >
          Use pontos para pagar menos na fatura
        </Text>
      </Box>
      <Box ml="nano" mr="nano" flex={1} justify="flex-start">
        <ListTextIcon
          items={items as any}
          type="list"
          ml="nano"
          mr="xs"
          mt="xxs"
        />
      </Box>
      <Box ml="smaller" mr="smaller">
        <Button
          text="Continuar"
          mt="large"
          mb="small"
          onPress={() => {}}
        />
      </Box>
    </Box>
  );
}

function SideBySideComparison() {
  const screen = useSDUIJsonEditor(onboardingCashback);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24 }}>
        <Text type="headingMDL" mb="nano">
          Side-by-Side: Real Screen vs SDUI
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Left: traditional React components with hardcoded data. Right: same
          visual result rendered entirely from JSON via the SDUI engine.
        </Text>

        <View style={{ flexDirection: 'row', gap: 24 }}>
          <View style={{ flex: 1, maxWidth: 420 }}>
            <Text type="subtitleXXL" mb="nano" align="center">
