          <View style={{ flex: 1, maxWidth: 420 }}>
            <Text type="subtitleXXL" mb="nano" align="center">
              SDUI from JSON
            </Text>
            <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
              <ScreenRenderer screen={screen} />
            </Box>
          </View>
        </View>

        <SeparatorHorizontal mv="xs" />

        <Box pd="innerSmall" bgColor="BRAND_COMPLEMENT_02" br="sm">
          <Text type="paragraphMDM" mb="xxxs">
            Key difference
          </Text>
          <Text type="bodyMD" color="INTENSE_COLOR_03">
            The left column requires code changes to update per-product content
