const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  // Demo story
  await page.goto('http://localhost:6006/iframe.html?id=sdui-onboarding--demo&viewMode=story');
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '.storybook/screenshots/sdui-onboarding-demo.png', fullPage: true });
  console.log('Screenshot: sdui-onboarding-demo.png');

  // Comparison story
  await page.goto('http://localhost:6006/iframe.html?id=sdui-onboarding--comparison&viewMode=story');
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '.storybook/screenshots/sdui-onboarding-comparison.png', fullPage: true });
  console.log('Screenshot: sdui-onboarding-comparison.png');

  await browser.close();
  console.log('Done');
})().catch(e => { console.error(e.message); process.exit(1); });
