import type { SDUIScreen } from '../models';

export const onboardingCashback: SDUIScreen = {
  id: 'onboarding-cashback',
  context: {
    pointsQuantity: 15320,
    conversionFactor: 0.01,
    formattedPrice: 'R$ 153,20',
    product: {
      name: 'Cashback na fatura',
      code: '209',
    },
  },
  header: {
    type: 'nav_header',
    props: {
      title: '{{product.name}}',
      iconLeft: 'icon-back',
    },
  },
  body: [
    {
      type: 'heading',
      props: {
        text: 'Use pontos para pagar menos na fatura',
        spacing: 'smaller',
      },
    },
    {
      type: 'list_text_icon',
      props: {
        items: [
          {
            type: 'default',
            icon: 'icon-switch-vertical',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description:
              'Cada {{pointsQuantity}} pontos valem {{formattedPrice}} no cashback',
          },
          {
            type: 'default',
            icon: 'icon-calendar',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description:
              'Você define quanto cashback quer aplicar na sua fatura aberta',
          },
          {
            type: 'default',
            icon: 'icon-payment-invoice',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description:
              'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
          },
          {
            type: 'default',
            icon: 'icon-clock',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description: 'O cashback acontece em até 72h',
          },
        ],
        type: 'list',
        ml: 'nano',
        mr: 'xs',
      },
    },
    {
      type: 'button',
      props: {
        text: 'Continuar',
        spacing: 'smaller',
      },
    },
  ],
};

